import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { useState } from "react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import type { ParseResult, WorkoutScheme } from "@/lib/scoring"
import { parseScore } from "@/lib/scoring"
import { cn } from "@/lib/utils"
import {
  enterSubmissionScoreFn,
  type EventDetails,
} from "@/server-fns/submission-verification-fns"
import {
  getSchemeLabel,
  getScoreHelpText,
  getScorePlaceholder,
} from "./score-entry-helpers"

interface EnterScoreFormProps {
  videoSubmissionId: string
  competitionId: string
  trackWorkoutId: string
  event: EventDetails
}

/**
 * First-time score entry for video submissions whose athlete uploaded a
 * video without filling in the score field. Renders in the no-score branch
 * of both the organizer and volunteer review surfaces; once submitted, the
 * route invalidates and the standard `VerificationControls` takes over.
 *
 * Mirrors the score-entry UX of `video-submission-form.tsx` — schema-aware
 * parsing, auto-derived cap status for time-with-cap, tiebreak input — so
 * reviewers enter scores through the same validation path as athletes.
 */
export function EnterScoreForm({
  videoSubmissionId,
  competitionId,
  trackWorkoutId,
  event,
}: EnterScoreFormProps) {
  const router = useRouter()
  const enterFn = useServerFn(enterSubmissionScoreFn)

  const scheme = event.workout.scheme as WorkoutScheme
  const roundsToScore = Math.max(1, event.workout.roundsToScore ?? 1)
  const isMultiRound = roundsToScore > 1
  const timeCap = event.workout.timeCap
  const tiebreakScheme = event.workout.tiebreakScheme as WorkoutScheme | null

  const [scoreInput, setScoreInput] = useState("")
  const [roundScoreInputs, setRoundScoreInputs] = useState<string[]>(() =>
    Array.from({ length: roundsToScore }, () => ""),
  )
  const [secondaryScore, setSecondaryScore] = useState("")
  const [tiebreakInput, setTiebreakInput] = useState("")
  const [reviewerNotes, setReviewerNotes] = useState("")
  const [noRepCount, setNoRepCount] = useState("")
  const [error, setError] = useState<string | null>(null)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [hasAttemptedSubmit, setHasAttemptedSubmit] = useState(false)

  const parseResult: ParseResult | null =
    !isMultiRound && scoreInput.trim()
      ? parseScore(scoreInput, scheme)
      : null

  const roundParseResults: (ParseResult | null)[] = isMultiRound
    ? roundScoreInputs.map((s) => (s.trim() ? parseScore(s, scheme) : null))
    : []

  const tiebreakParseResult: ParseResult | null =
    tiebreakScheme && tiebreakInput.trim()
      ? parseScore(tiebreakInput, tiebreakScheme)
      : null

  // Auto-derive cap status from parsed time vs the workout's time cap —
  // mirrors video-submission-form.tsx so reviewers don't need a separate
  // status picker.
  const scoreStatus: "scored" | "cap" = (() => {
    if (
      parseResult?.isValid &&
      parseResult.encoded !== null &&
      scheme === "time-with-cap" &&
      timeCap
    ) {
      const capMs = timeCap * 1000
      if (parseResult.encoded >= capMs) return "cap"
    }
    return "scored"
  })()

  const showSecondaryInput =
    !isMultiRound && scheme === "time-with-cap" && scoreStatus === "cap"

  const canSubmit = isMultiRound
    ? roundScoreInputs.every((s) => s.trim().length > 0)
    : scoreInput.trim().length > 0

  async function handleSubmit() {
    setError(null)
    setHasAttemptedSubmit(true)

    if (isMultiRound) {
      for (let i = 0; i < roundScoreInputs.length; i++) {
        const input = roundScoreInputs[i]
        if (!input.trim()) {
          setError(`Please enter a score for round ${i + 1}`)
          return
        }
        const r = parseScore(input, scheme)
        if (!r.isValid) {
          setError(`Round ${i + 1}: ${r.error ?? "invalid score"}`)
          return
        }
      }
    } else {
      if (!scoreInput.trim()) {
        setError("Please enter a score")
        return
      }
      if (!parseResult?.isValid) {
        setError(parseResult?.error ?? "Invalid score")
        return
      }
    }

    if (tiebreakScheme && tiebreakInput.trim() && !tiebreakParseResult?.isValid) {
      setError(tiebreakParseResult?.error ?? "Invalid tiebreak")
      return
    }

    setIsSubmitting(true)
    try {
      if (isMultiRound) {
        await enterFn({
          data: {
            competitionId,
            trackWorkoutId,
            videoSubmissionId,
            roundScores: roundScoreInputs.map((s, i) => ({
              roundNumber: i + 1,
              score: s.trim(),
            })),
            tieBreakScore: tiebreakInput.trim() || undefined,
            reviewerNotes: reviewerNotes.trim() || undefined,
            noRepCount: noRepCount
              ? Number.parseInt(noRepCount, 10)
              : undefined,
          },
        })
      } else {
        await enterFn({
          data: {
            competitionId,
            trackWorkoutId,
            videoSubmissionId,
            score: scoreInput.trim(),
            scoreStatus,
            secondaryScore:
              scoreStatus === "cap"
                ? secondaryScore.trim() || undefined
                : undefined,
            tieBreakScore: tiebreakInput.trim() || undefined,
            reviewerNotes: reviewerNotes.trim() || undefined,
            noRepCount: noRepCount
              ? Number.parseInt(noRepCount, 10)
              : undefined,
          },
        })
      }
      await router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to enter score")
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Enter Score</CardTitle>
        <CardDescription>
          The athlete uploaded a video without filling in the score field.
          Watch the video and enter what they actually scored — this creates
          the missing scores row and marks the submission reviewed.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {error && (
          <div className="rounded-md border border-destructive/50 bg-destructive/10 p-2 text-sm text-destructive">
            {error}
          </div>
        )}

        {isMultiRound ? (
          <div className="space-y-3">
            <Label>{getSchemeLabel(scheme)} per Round</Label>
            {roundScoreInputs.map((input, i) => {
              const roundResult = roundParseResults[i]
              return (
                <div key={`enter-r-${i + 1}`} className="space-y-1">
                  <Label
                    htmlFor={`enter-round-${i}`}
                    className="text-sm font-normal text-muted-foreground"
                  >
                    Round {i + 1}
                  </Label>
                  <Input
                    id={`enter-round-${i}`}
                    value={input}
                    onChange={(e) => {
                      const next = [...roundScoreInputs]
                      next[i] = e.target.value
                      setRoundScoreInputs(next)
                    }}
                    placeholder={getScorePlaceholder(scheme)}
                    className={cn(
                      "font-mono",
                      ((roundResult?.error && !roundResult?.isValid) ||
                        (hasAttemptedSubmit && !input.trim())) &&
                        "border-destructive",
                    )}
                    disabled={isSubmitting}
                  />
                  {roundResult?.isValid && (
                    <p className="text-xs text-green-600 dark:text-green-400">
                      Parsed as: {roundResult.formatted}
                    </p>
                  )}
                  {roundResult?.error && (
                    <p className="text-xs text-destructive">
                      {roundResult.error}
                    </p>
                  )}
                </div>
              )
            })}
            {getScoreHelpText(scheme, timeCap) && (
              <p className="text-xs text-muted-foreground">
                {getScoreHelpText(scheme, timeCap)}
              </p>
            )}
            {scheme === "time-with-cap" && timeCap ? (
              <p className="text-[11px] text-muted-foreground">
                Status is derived per round from the time vs the per-round cap.
              </p>
            ) : null}
          </div>
        ) : (
          <div className="space-y-2">
            <Label htmlFor="enter-score">{getSchemeLabel(scheme)}</Label>
            <Input
              id="enter-score"
              value={scoreInput}
              onChange={(e) => setScoreInput(e.target.value)}
              placeholder={getScorePlaceholder(scheme)}
              className={cn(
                "font-mono",
                ((parseResult?.error && !parseResult?.isValid) ||
                  (hasAttemptedSubmit && !scoreInput.trim())) &&
                  "border-destructive",
              )}
              disabled={isSubmitting}
            />
            {getScoreHelpText(scheme, timeCap) && (
              <p className="text-xs text-muted-foreground">
                {getScoreHelpText(scheme, timeCap)}
              </p>
            )}
            {parseResult?.isValid && (
              <p className="text-xs text-green-600 dark:text-green-400">
                Parsed as: {parseResult.formatted}
                {scoreStatus === "cap" && " (Time Cap)"}
              </p>
            )}
            {parseResult?.error && (
              <p className="text-xs text-destructive">{parseResult.error}</p>
            )}
          </div>
        )}

        {!isMultiRound && scoreStatus === "cap" && (
          <p className="text-xs text-amber-600 dark:text-amber-400">
            Time cap hit. Enter the reps completed at the cap below.
          </p>
        )}
        {showSecondaryInput && (
          <div className="space-y-2">
            <Label htmlFor="enter-secondary">Reps Completed at Cap</Label>
            <Input
              id="enter-secondary"
              type="number"
              value={secondaryScore}
              onChange={(e) => setSecondaryScore(e.target.value)}
              placeholder="e.g., 150"
              min="0"
              disabled={isSubmitting}
            />
            <p className="text-xs text-muted-foreground">
              Total reps/work completed when the time cap hit
            </p>
          </div>
        )}

        {tiebreakScheme && (
          <div className="space-y-2">
            <Label htmlFor="enter-tiebreak">
              Tiebreak ({tiebreakScheme === "time" ? "Time" : "Reps/Weight"})
            </Label>
            <Input
              id="enter-tiebreak"
              value={tiebreakInput}
              onChange={(e) => setTiebreakInput(e.target.value)}
              placeholder={
                tiebreakScheme === "time" ? "e.g., 3:45" : "e.g., 100"
              }
              className={cn(
                "font-mono",
                tiebreakParseResult?.error &&
                  !tiebreakParseResult?.isValid &&
                  "border-destructive",
              )}
              disabled={isSubmitting}
            />
            {tiebreakParseResult?.isValid && (
              <p className="text-xs text-green-600 dark:text-green-400">
                Parsed as: {tiebreakParseResult.formatted}
              </p>
            )}
            {tiebreakParseResult?.error && (
              <p className="text-xs text-destructive">
                {tiebreakParseResult.error}
              </p>
            )}
            <p className="text-xs text-muted-foreground">
              {tiebreakScheme === "time"
                ? "Time to complete specified reps/work"
                : "Reps or weight completed for tiebreak"}
            </p>
          </div>
        )}

        <div className="space-y-2">
          <Label htmlFor="enter-no-rep" className="text-xs">
            No-rep count (optional)
          </Label>
          <Input
            id="enter-no-rep"
            value={noRepCount}
            onChange={(e) => setNoRepCount(e.target.value)}
            placeholder="e.g. 12"
            type="number"
            min="0"
            className="font-mono"
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="enter-notes" className="text-xs">
            Note to athlete (optional)
          </Label>
          <Textarea
            id="enter-notes"
            value={reviewerNotes}
            onChange={(e) => setReviewerNotes(e.target.value)}
            placeholder="Why this score was entered..."
            rows={2}
            className="text-sm"
          />
        </div>

        <Button
          className="w-full"
          onClick={handleSubmit}
          disabled={!canSubmit || isSubmitting}
        >
          {isSubmitting ? "Saving..." : "Save Score"}
        </Button>
      </CardContent>
    </Card>
  )
}

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { useState } from "react"
import { toast } from "sonner"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { decodeScore } from "@/lib/scoring/decode"
import type { WorkoutScheme } from "@/lib/scoring/types"
import { deleteCompetitionScoreFn } from "@/server-fns/competition-score-fns"
import { OrganizerScoreEditor } from "./organizer-score-editor"
import {
  type AthleteDetailEvent,
  type AthleteDetailMember,
  type AthleteDetailScore,
  memberDisplayName,
} from "./types"

interface EventScoreCardProps {
  event: AthleteDetailEvent
  registrationId: string
  competitionId: string
  organizingTeamId: string
  divisionId: string | null
  scores: AthleteDetailScore[]
  members: AthleteDetailMember[]
}

function safeDecode(value: number, scheme: string): string {
  try {
    return decodeScore(value, scheme as WorkoutScheme, { compact: false })
  } catch {
    return String(value)
  }
}

export function EventScoreCard({
  event,
  registrationId,
  competitionId,
  organizingTeamId,
  divisionId,
  scores,
  members,
}: EventScoreCardProps) {
  const router = useRouter()
  const deleteScore = useServerFn(deleteCompetitionScoreFn)

  const captain = members.find((m) => m.isCaptain) ?? members[0]
  const captainScore = captain
    ? scores.find((s) => s.userId === captain.userId)
    : null

  const [editing, setEditing] = useState(false)
  const [deleteOpen, setDeleteOpen] = useState(false)
  const [isDeleting, setIsDeleting] = useState(false)

  const handleDelete = async () => {
    if (!captain) return
    setIsDeleting(true)
    try {
      await deleteScore({
        data: {
          organizingTeamId,
          competitionId,
          trackWorkoutId: event.trackWorkoutId,
          userId: captain.userId,
        },
      })
      toast.success("Score deleted")
      setDeleteOpen(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to delete score",
      )
    } finally {
      setIsDeleting(false)
    }
  }

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-3 flex-wrap">
            <div className="min-w-0 space-y-1">
              <CardTitle className="truncate">{event.workoutName}</CardTitle>
              <CardDescription className="text-xs">
                Scheme: <span className="font-mono">{event.scheme}</span>
                {event.timeCap ? (
                  <span className="ml-2">Cap: {event.timeCap}s</span>
                ) : null}
              </CardDescription>
            </div>
            {captainScore && !editing && (
              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setEditing(true)}
                >
                  Edit score
                </Button>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setDeleteOpen(true)}
                  className="text-destructive hover:text-destructive hover:bg-destructive/10"
                >
                  Delete
                </Button>
              </div>
            )}
          </div>
        </CardHeader>
        <CardContent className="space-y-3">
          {!captainScore && !editing && (
            <div className="flex items-center justify-between rounded-md border border-dashed p-4">
              <div className="text-sm text-muted-foreground">
                No score entered for this event.
              </div>
              <Button size="sm" onClick={() => setEditing(true)}>
                Enter score
              </Button>
            </div>
          )}

          {captainScore && !editing && (
            <div className="space-y-2">
              <div className="flex items-center gap-3 flex-wrap">
                <span className="text-2xl font-mono font-bold">
                  {captainScore.scoreValue !== null
                    ? safeDecode(captainScore.scoreValue, event.scheme)
                    : "—"}
                </span>
                {captainScore.scoreStatus !== "scored" && (
                  <Badge variant="secondary" className="text-xs">
                    {captainScore.scoreStatus === "cap"
                      ? "Capped"
                      : captainScore.scoreStatus.toUpperCase()}
                  </Badge>
                )}
                {captainScore.tieBreakScore != null && (
                  <span className="text-xs text-muted-foreground font-mono">
                    Tiebreak:{" "}
                    {safeDecode(captainScore.tieBreakScore, event.scheme)}
                  </span>
                )}
              </div>
              {captainScore.scoreRounds.length > 1 && (
                <div className="space-y-0.5">
                  {captainScore.scoreRounds.map((round) => (
                    <div
                      key={round.roundIndex}
                      className="flex items-center gap-2 text-xs text-muted-foreground font-mono"
                    >
                      <span className="uppercase tracking-wider w-8">
                        R{round.roundIndex}
                      </span>
                      <span>{safeDecode(round.scoreValue, event.scheme)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {editing && captain && (
            <OrganizerScoreEditor
              event={event}
              competitionId={competitionId}
              organizingTeamId={organizingTeamId}
              registrationId={registrationId}
              userId={captain.userId}
              divisionId={divisionId}
              existing={
                captainScore
                  ? {
                      scoreValue: captainScore.scoreValue,
                      scoreStatus: captainScore.scoreStatus,
                      tieBreakScore: captainScore.tieBreakScore,
                      secondaryScore: captainScore.secondaryScore,
                      scoreRounds: captainScore.scoreRounds,
                    }
                  : null
              }
              onCancel={() => setEditing(false)}
              onSaved={() => setEditing(false)}
            />
          )}
        </CardContent>
      </Card>

      <AlertDialog open={deleteOpen} onOpenChange={setDeleteOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete score</AlertDialogTitle>
            <AlertDialogDescription>
              Delete the score for {captain ? memberDisplayName(captain) : ""}{" "}
              on <strong>{event.workoutName}</strong>? This removes the score
              record entirely.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              disabled={isDeleting}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isDeleting ? "Deleting..." : "Delete"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  )
}

/**
 * Score formatting: converts Score objects to display strings
 */

import { decodeScore } from "../decode"
import type { FormatOptions, Score, ScoreRound, WorkoutScheme } from "../types"
import { formatStatus, isSpecialStatus } from "./status"

/**
 * Format a complete Score object for display.
 *
 * @param score - Score object to format
 * @param options - Format options
 *
 * @example
 * formatScore({ scheme: "time", scoreType: "min", value: 754567, status: "scored" })
 * // → "12:34.567"
 *
 * formatScore({
 *   scheme: "time-with-cap",
 *   scoreType: "min",
 *   value: null,
 *   status: "cap",
 *   timeCap: { ms: 900000, secondaryValue: 142 }
 * })
 * // → "CAP (142 reps)"
 *
 * formatScore({ scheme: "load", scoreType: "max", value: 102058, status: "scored" },
 *             { weightUnit: "lbs", includeUnit: true })
 * // → "225 lbs"
 */
export function formatScore(score: Score, options?: FormatOptions): string {
  const showStatus = options?.showStatus ?? true

  // Handle special statuses
  if (isSpecialStatus(score.status)) {
    return formatSpecialStatus(score, options, showStatus)
  }

  // Normal scored result
  if (score.value === null) {
    return "N/A"
  }

  return decodeScore(score.value, score.scheme, options)
}

/**
 * Format scores with special status (cap, dq, withdrawn).
 */
function formatSpecialStatus(
  score: Score,
  options?: FormatOptions,
  showStatus: boolean = true,
): string {
  const statusPrefix = showStatus ? formatStatus(score.status) : ""

  switch (score.status) {
    case "cap": {
      // Single-round capped: `timeCap.secondaryValue` holds reps at cap.
      if (score.timeCap?.secondaryValue !== undefined) {
        const repsFormatted = `${score.timeCap.secondaryValue} reps`
        return showStatus ? `${statusPrefix} (${repsFormatted})` : repsFormatted
      }
      // Multi-round capped: `value` is the summed total across rounds
      // (per-round caps enforced separately), so surface it.
      if (score.value !== null) {
        const decoded = decodeScore(score.value, score.scheme, options)
        return showStatus ? `${statusPrefix} (${decoded})` : decoded
      }
      return statusPrefix || "CAP"
    }

    case "dq":
      return statusPrefix || "DQ"

    case "withdrawn":
      return statusPrefix || "WD"

    default:
      return score.value !== null
        ? decodeScore(score.value, score.scheme, options)
        : "N/A"
  }
}

/**
 * Format a score for compact leaderboard display.
 * Similar to formatScore but with compact option enabled by default.
 *
 * @example
 * formatScoreCompact({ scheme: "time", value: 754000, ... })
 * // → "12:34" (no milliseconds shown)
 */
export function formatScoreCompact(
  score: Score,
  options?: FormatOptions,
): string {
  return formatScore(score, { ...options, compact: true })
}

/**
 * Format individual rounds for display.
 *
 * @param rounds - Array of score rounds
 * @param scheme - Default scheme for rounds
 * @param options - Format options
 *
 * @example
 * formatRounds(
 *   [{ roundNumber: 1, value: 102058 }, { roundNumber: 2, value: 106594 }],
 *   "load",
 *   { weightUnit: "lbs", includeUnit: true }
 * )
 * // → ["225 lbs", "235 lbs"]
 */
export function formatRounds(
  rounds: ScoreRound[],
  scheme: WorkoutScheme,
  options?: FormatOptions,
): string[] {
  return rounds.map((round) => {
    const effectiveScheme = round.schemeOverride ?? scheme

    // Handle rounds with special status
    if (round.status && isSpecialStatus(round.status)) {
      const statusStr = formatStatus(round.status)
      if (round.secondaryValue !== undefined) {
        return `${statusStr} (${round.secondaryValue})`
      }
      return statusStr
    }

    return decodeScore(round.value, effectiveScheme, options)
  })
}

/**
 * Format a score with tiebreak information.
 *
 * @example
 * formatScoreWithTiebreak(score)
 * // → "5+12 (TB: 8:30)"
 */
export function formatScoreWithTiebreak(
  score: Score,
  options?: FormatOptions,
): string {
  const mainScore = formatScore(score, options)

  if (!score.tiebreak) {
    return mainScore
  }

  const tiebreakFormatted =
    score.tiebreak.scheme === "time"
      ? decodeScore(score.tiebreak.value, "time", { compact: true })
      : score.tiebreak.value.toString()

  return `${mainScore} (TB: ${tiebreakFormatted})`
}

/**
 * Format a score for display in a results list.
 * Includes status, main score, and tiebreak if present.
 *
 * @example
 * formatScoreForList(score)
 * // → "12:34.567" or "CAP (142 reps)" or "5+12 (TB: 8:30)"
 */
export function formatScoreForList(
  score: Score,
  options?: FormatOptions,
): string {
  if (score.tiebreak) {
    return formatScoreWithTiebreak(score, options)
  }
  return formatScore(score, options)
}

export interface Score {
  // Classification
  scheme: WorkoutScheme
  scoreType: ScoreType

  // Primary aggregated value (encoded as integer)
  value: number | null
  status: ScoreStatus

  // Individual rounds (optional)
  rounds?: ScoreRound[]

  // Tiebreak
  tiebreak?: {
    scheme: TiebreakScheme
    value: number
  }

  // Time cap handling (for time-with-cap)
  timeCap?: {
    /** Time cap in milliseconds */
    ms: number
    /** Reps completed when capped */
    secondaryValue: number
  }

  /**
   * Per-round cap counts for multi-round `time-with-cap` workouts.
   * When present, `computeSortKey` uses `cappedRoundCount` as a tiebreaker
   * *above* the summed total within the "cap" status bucket, so scores with
   * fewer capped rounds always rank ahead of scores with more capped rounds.
   */
  cappedRoundCount?: number
  totalRoundCount?: number

  // Computed sort key (for database storage)
  sortKey?: bigint
}

// ============ Input Types ============

/** Input for a single round */
export interface RoundInput {
  /** User input: "225", "12:34", etc. */
  raw: string
  /** Override scheme for this round */
  schemeOverride?: WorkoutScheme
  /** Unit for load/distance */
  unit?: WeightUnit | DistanceUnit
}

/** Input for creating/updating a score */
export interface ScoreInput {
  scheme: WorkoutScheme
  /** Defaults based on scheme if not provided */
  scoreType?: ScoreType

  // Either a single value OR multiple rounds
  /** Single aggregated value (user input string) */
  value?: string

